import { Injectable, signal, computed, inject } from "@angular/core";
import { Router } from "@angular/router";
import type { Page, Layout, UiSchema } from "../types";
import { SchemaRendererService } from "../schema-renderer/schema-renderer.service";
import type { RouteMatch } from "./route-match";

@Injectable({ providedIn: "root" })
export class SchemaRouterService {
  private renderer = inject(SchemaRendererService);
  private ngRouter = inject(Router);

  private _currentPage = signal<Page | null>(null);
  private _currentLayout = signal<Layout | null>(null);
  private _currentRoute = signal<string | null>(null);
  private _routeParams = signal<Record<string, string>>({});

  readonly currentPage = this._currentPage.asReadonly();
  readonly currentLayout = this._currentLayout.asReadonly();
  readonly currentRoute = this._currentRoute.asReadonly();
  readonly routeParams = this._routeParams.asReadonly();

  private schema: UiSchema | null = null;
  private routeRegistry = new Map<string, Page>();

  readonly currentPageSignal = computed(() => this._currentPage());
  readonly currentLayoutSignal = computed(() => this._currentLayout());

  setSchema(schema: UiSchema): void {
    this.schema = schema;
    this.renderer.setSchema(schema);
    this.buildRouteRegistry();
  }

  async loadSchema(mode: "embedded" | "file" | "cloud", source?: string): Promise<void> {
    switch (mode) {
      case "embedded":
        break;
      case "file":
        break;
      case "cloud":
        break;
    }
  }

  async navigate(route: string, params?: Record<string, string>): Promise<boolean> {
    const match = this.resolveRoute(route, params);

    if (!match) {
      return false;
    }

    if (match.page.layout) {
      const layout = this.schema?.layouts.find((l) => l.id === match.page.layout);
      this._currentLayout.set(layout ?? null);
    }

    this._currentPage.set(match.page);
    this._currentRoute.set(route);
    this._routeParams.set(params || {});

    return true;
  }

  setCurrentPage(page: Page): void {
    this._currentPage.set(page);
  }

  setCurrentRoute(route: string): void {
    this._currentRoute.set(route);
  }

  getPage(pageId: string): Page | undefined {
    return this.schema?.pages.find((p) => p.id === pageId);
  }

  getPageByRoute(route: string): Page | undefined {
    return this.routeRegistry.get(route);
  }

  resolveRoute(route: string, params?: Record<string, string>): RouteMatch | null {
    const page = this.routeRegistry.get(route);

    if (!page) {
      return null;
    }

    return {
      page,
      params: params || {},
      guards: [],
    };
  }

  getAllRoutes(): Array<{ route: string; page: Page }> {
    return Array.from(this.routeRegistry.entries()).map(([route, page]) => ({
      route,
      page,
    }));
  }

  buildRouteRegistry(): void {
    if (!this.schema) return;

    this.routeRegistry.clear();

    for (const page of this.schema.pages) {
      if (page.route) {
        this.routeRegistry.set(page.route, page);
      }
    }
  }

  updateRouteParam(key: string, value: string): void {
    this._routeParams.update((params) => ({
      ...params,
      [key]: value,
    }));
  }

  clearRouteParams(): void {
    this._routeParams.set({});
  }

  generateRoute(pageId: string, params?: Record<string, string>): string | null {
    const page = this.getPage(pageId);
    if (!page?.route) return null;

    if (!params) return page.route;

    let route = page.route;
    for (const [key, value] of Object.entries(params)) {
      route = route.replace(`:${key}`, value);
    }

    return route;
  }

  matchRoute(path: string): RouteMatch | null {
    if (!this.schema) return null;

    for (const page of this.schema.pages) {
      if (!page.route) continue;

      const pattern = this.routeToRegex(page.route);
      const match = path.match(pattern);

      if (match) {
        const params: Record<string, string> = {};
        const paramNames = this.extractParamNames(page.route);

        for (let i = 0; i < paramNames.length; i++) {
          params[paramNames[i]] = match[i + 1];
        }

        return {
          page,
          params,
          guards: [],
        };
      }
    }

    return null;
  }

  private routeToRegex(route: string): RegExp {
    const escaped = route.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const pattern = escaped.replace(/:([^/]+)/g, "([^/]+)");
    return new RegExp(`^${pattern}$`);
  }

  private extractParamNames(route: string): string[] {
    const matches = route.match(/:([^/]+)/g);
    return matches ? matches.map((m) => m.slice(1)) : [];
  }
}
