import {
  Component,
  Input,
  ViewChild,
  ElementRef,
  AfterViewInit,
  OnDestroy,
  inject,
  signal,
  effect,
} from "@angular/core";
import { CommonModule } from "@angular/common";
import { SchemaRouterService } from "./schema-router.service";
import { SchemaRendererService } from "../schema-renderer/schema-renderer.service";

@Component({
  selector: "lib-schema-route-viewer",
  standalone: true,
  imports: [CommonModule],
  template: `
    <div #container class="schema-route-viewer">
      @if (isLoading()) {
        <div class="schema-loading">
          <span>Loading...</span>
        </div>
      }
      @if (error()) {
        <div class="schema-error">
          {{ error() }}
        </div>
      }
    </div>
  `,
  styles: [`
    :host {
      display: block;
      width: 100%;
      height: 100%;
    }
    .schema-route-viewer {
      width: 100%;
      height: 100%;
      position: relative;
    }
    .schema-loading,
    .schema-error {
      display: flex;
      align-items: center;
      justify-content: center;
      width: 100%;
      height: 100%;
    }
    .schema-error {
      color: var(--color-error, #ef4444);
    }
  `],
})
export class SchemaRouteViewerComponent implements AfterViewInit, OnDestroy {
  @Input() route = "";

  @ViewChild("container") containerRef!: ElementRef<HTMLElement>;

  private router = inject(SchemaRouterService);
  private renderer = inject(SchemaRendererService);

  readonly isLoading = signal(false);
  readonly error = signal<string | null>(null);

  private isInitialized = false;

  constructor() {
    effect(() => {
      const currentRoute = this.router.currentRoute();
      if (currentRoute && this.isInitialized) {
        this.renderCurrentRoute();
      }
    });
  }

  ngAfterViewInit(): void {
    this.isInitialized = true;

    if (this.route) {
      this.loadRoute(this.route);
    } else {
      this.renderCurrentRoute();
    }
  }

  ngOnDestroy(): void {
    this.renderer.clear();
  }

  async loadRoute(route: string): Promise<void> {
    this.isLoading.set(true);
    this.error.set(null);

    try {
      await this.router.navigate(route);
      await this.renderCurrentRoute();
    } catch (err) {
      this.error.set(err instanceof Error ? err.message : "Failed to load route");
    } finally {
      this.isLoading.set(false);
    }
  }

  private async renderCurrentRoute(): Promise<void> {
    const page = this.router.currentPage();
    const container = this.containerRef?.nativeElement;

    if (!page || !container) {
      return;
    }

    try {
      await this.renderer.renderPage(page.id, container);
    } catch (err) {
      this.error.set(err instanceof Error ? err.message : "Failed to render page");
    }
  }
}
