import { Injectable } from "@angular/core";
import { SignalStore, createSignalStore } from "../../../core-storage/signal-store";

@Injectable({ providedIn: "root" })
export class SignalStoreService {
  private store = createSignalStore();

  set(key: string, value: unknown): void {
    this.store.set(key, value);
  }

  get(key: string): unknown {
    return this.store.get(key);
  }

  update(key: string, fn: (value: unknown) => unknown): void {
    this.store.update(key, fn);
  }

  delete(key: string): void {
    this.store.delete(key);
  }

  keys(): string[] {
    return this.store.keys();
  }

  toJSON(): Record<string, unknown> {
    return this.store.toJSON();
  }

  fromJSON(json: Record<string, unknown>): void {
    this.store.fromJSON(json);
  }

  subscribe(callback: (key: string, value: unknown) => void): () => void {
    return this.store.subscribe(callback);
  }
}
